// รับได้ทั้ง object และ string (รวมถึง Buffer)
let p = msg.payload;
if (Buffer.isBuffer(p)) p = p.toString();
if (typeof p === 'string') {
  try { p = JSON.parse(p); } catch(e){
    msg.statusCode = 400;
    msg.payload = { ok:false, error:"invalid JSON body" };
    return [null, msg];
  }
}
if (!p || !p.image_b64) {
  msg.statusCode = 400;
  msg.payload = { ok:false, error:"image_b64 missing" };
  return [null, msg];
}
const plant_id = p.plant_id || "PLANT-01";
const tray_id  = p.tray_id  || "TRAY-01";
const cell_id  = p.cell_id  || "A1";
const temp_c   = (p.temp_c!=null)   ? Number(p.temp_c)   : undefined;
const humidity = (p.humidity!=null) ? Number(p.humidity) : undefined;
// decode base64 (รองรับ data URL)
let b64 = p.image_b64; const comma = b64.indexOf(','); if (comma>0) b64 = b64.slice(comma+1);
const buffer = Buffer.from(b64,'base64');
// meta + buffer
msg.meta = { plant_id, tray_id, cell_id, temp_c, humidity, ts: Date.now() };
msg.imageBuffer = buffer;
return [msg, null];

// เซฟลง C:/AppServ/www/minijec/media/YYYY/MM/DD/
const baseDir = "C:/AppServ/www/minijec/media";
const d = new Date();
const pad = n => String(n).padStart(2,'0');
const yyyy = d.getFullYear();
const mm = pad(d.getMonth()+1);
const dd = pad(d.getDate());
const ts = Math.floor(d.getTime()/1000);
const fn = `${msg.meta.plant_id}_${ts}.jpg`;
msg.saveDir = `${baseDir}/${yyyy}/${mm}/${dd}`;
msg.filepath = `${msg.saveDir}/${fn}`;
msg.public_url = `/minijec/media/${yyyy}/${mm}/${dd}/${fn}`;
msg.payload = msg.imageBuffer;  // ส่งบัฟเฟอร์ไป node file
return msg;

const img = msg.filepath;
const script = 'C:/Users/Lenovo/analyze.py';
msg.payload = `"${script}" "${img}" --mode otsu --kopen 3 --kclose 3 --area-min 80`;
return msg;

// Compose Influx Point (robust) — fixed: avoid name 'env'
const pathLike = (v) => (typeof v === 'string') ? v : '';

const r = (msg && typeof msg.payload === 'object') ? msg.payload : {};
let meta = (msg && typeof msg.meta === 'object') ? msg.meta : {};

// อย่าใช้ชื่อ 'env' — ใน Function node มี 'env' อยู่แล้ว
const envLast = global.get('env_last') || {};
if (meta.temp_c == null && typeof envLast.temp_c === 'number') meta.temp_c = envLast.temp_c;
if (meta.humidity == null && typeof envLast.humidity === 'number') meta.humidity = envLast.humidity;

// ถ้าไม่มี plant/tray/cell ใน meta ให้ถอดจากชื่อไฟล์ (หลัง rename)
let plant_id = meta.plant_id;
let tray_id = meta.tray_id;
let cell_id = meta.cell_id;

if (!plant_id || !tray_id || !cell_id) {
  const fp = pathLike(msg.filepath);
  const fn = fp.split(/[\\/]/).pop();  // basename
  // ชื่อไฟล์มาตรฐาน: PLANT-01_T-01_C-XX_1758943311.jpg
  const mm = fn && fn.match(/^(PLANT-\d+)_T-(\d{2})_C-([A-Za-z0-9-]+)_(\d+)\.(jpg|jpeg|png)$/i);
  if (mm) {
    plant_id = plant_id || mm[1];
    tray_id = tray_id || ('TRAY-' + mm[2]);
    cell_id = cell_id || mm[3];
  }
}

// fallback สุดท้าย
plant_id = plant_id || 'PLANT-01';
tray_id = tray_id || 'TRAY-01';
cell_id = cell_id || 'A1';

// รวม fields ตัวเลขจากผล analyze + ENV
const fields = {};
if (r.area_px != null) fields.area_px = Number(r.area_px);
if (r.greenness != null) fields.greenness = Number(r.greenness);
if (r.seed_count != null) fields.seed_count = Number(r.seed_count);
if (meta.temp_c != null) fields.temp_c = Number(meta.temp_c);
if (meta.humidity != null) fields.humidity = Number(meta.humidity);

// ถ้าไม่มีฟิลด์ตัวเลขเลย ก็ไม่ต้องเขียน Influx
if (Object.keys(fields).length === 0) {
  node.status({ fill: "yellow", shape: "ring", text: "no numeric fields" });
  return null;
}

// ส่งเข้า Influx
msg.measurement = 'growth';
msg.tags = { plant_id, tray_id, cell_id };
msg.payload = fields;

node.status({ fill: "green", shape: "dot", text: `${tray_id}/${cell_id} → ${Object.keys(fields).join(',')}` });
return msg;

const CHAT_ID = 1520038645; // ← ใส่ chat id ของคุณ
const f = msg.payload || {}; const m = msg.meta || {};
const alerts = [];
if (typeof f.greenness==='number' && f.greenness < 0.10) alerts.push(`⚠️ Greenness ต่ำ ${f.greenness.toFixed(2)} — ${m.plant_id||'-'}/${m.tray_id||'-'}-${m.cell_id||'-'}`);
if (typeof f.temp_c==='number' && f.temp_c > 35) alerts.push(`🔥 Temp สูง ${f.temp_c.toFixed(1)}°C — ${m.plant_id||'-'}`);
if (alerts.length===0) return null;
msg.payload = { chatId: CHAT_ID, type:'message', content: alerts.join('\n') };
return msg;

const d = (typeof msg.payload==='object'&&msg.payload)? msg.payload : {};
msg.headers = { 'Content-Type':'application/json; charset=utf-8', 'Access-Control-Allow-Origin':'*' };
msg.payload = { ok:true, public_url: msg.public_url||null, analyze: { area_px: d.area_px??null, greenness: d.greenness??null, seed_count: d.seed_count??null } };
return msg;

// รับข้อความจาก Serial ทีละบรรทัด
let line = (msg.payload || "").toString().trim();
if (!line) return null;

// เก็บ env ต่อถาด
let env_by_tray = flow.get('env_by_tray') || {};
let last_tray = flow.get('last_tray') || 1;

// config พื้นฐาน
const PLANT_ID = "PLANT-01";

// helper
const pad2 = n => String(n).padStart(2, '0');

// ----- กรณี CAPTURE N -----
let m1 = line.match(/^CAPTURE\s+(\d+)/i);
if (m1) {
    const trayNum = parseInt(m1[1], 10);
    flow.set('last_tray', trayNum);

    // ดึง ENV ล่าสุดของถาดนี้ ถ้าไม่มีใช้ของ global/ล่าสุด
    const env = env_by_tray[trayNum] || env_by_tray._last || {};

    // แนบ meta ใส่ลง msg เพื่อนำไปใช้ downstream ทั้ง capture/analyze/influx
    msg.meta = {
        plant_id: PLANT_ID,
        tray_id: "TRAY-" + pad2(trayNum),
        cell_id: "A1",
        temp_c: (typeof env.temp_c === 'number') ? env.temp_c : undefined,
        humidity: (typeof env.humidity === 'number') ? env.humidity : undefined,
        ts: Date.now()
    };

    // เตรียมคำสั่ง capture.py (เหมือนเดิมของคุณ)
    msg.payload = `"C:/Users/Lenovo/capture.py" --index 1 --base "C:/AppServ/www/minijec/media" --daily`;
    return msg;
}

// ----- กรณี ENV temp_c=.. humidity=.. -----
let m2 = line.match(/^ENV\s+temp_c=([0-9]+(?:\.[0-9]+)?)\s+humidity=([0-9]+)/i);
if (m2) {
    const t = parseFloat(m2[1]);
    const h = parseInt(m2[2], 10);

    // ผูก ENV กับถาดล่าสุด (จาก CAPTURE ก่อนหน้า)
    env_by_tray[last_tray] = { temp_c: t, humidity: h, ts: Date.now() };
    env_by_tray._last = { temp_c: t, humidity: h, ts: Date.now(), tray: last_tray };

    flow.set('env_by_tray', env_by_tray);
    // ไม่ต้องส่งต่อไปไหน (แค่เก็บค่า)
    return null;
}

// อย่างอื่น log ดูเฉยๆ
node.warn("Unknown serial line: " + line);
return null;

// ใช้ filepath จาก msg (หลัง Rename) เป็นหลัก และซ่อม drive letter ถ้าหาย
function fixWinPath(p) {
    if (!p) return p;
    if (Buffer.isBuffer(p)) p = p.toString();
    p = String(p).replace(/\\/g, '/');            // normalize
    if (/^:[/]/.test(p)) p = 'C' + p;             // แก้เคส ":/AppServ/..." → "C:/AppServ/..."
    return p;
}

let fp = msg.filepath;

// เผื่อบางกรณีโหนดก่อนหน้าใส่ไว้ใน payload (จาก Parse JSON capture)
if (!fp && msg.payload) {
    try {
        const p = (typeof msg.payload === 'string') ? JSON.parse(msg.payload) : msg.payload;
        if (p && typeof p.filepath === 'string') fp = p.filepath;
    } catch (_) { }
}

fp = fixWinPath(fp);

if (!fp) {
    node.error("analyze: filepath missing");
    return null;
}

msg.filepath = fp;  // เก็บกลับให้โหนดถัดไปใช้

const script = 'C:/Users/Lenovo/analyze.py';
msg.payload = `"${script}" "${fp}" --mode otsu --kopen 3 --kclose 3 --area-min 80`;
return msg;

// รับ ENV temp_c=30.3 humidity=70 → เก็บ global สำหรับ /api/summary
if (typeof msg.payload === "string") {
    const m = msg.payload.match(/^ENV\s+temp_c=([0-9.]+)\s+humidity=([0-9]+)/i);
    if (m) {
        const temp = parseFloat(m[1]);
        const hum = parseInt(m[2], 10);
        const env_last = { temp_c: temp, humidity: hum, ts: Date.now() };
        global.set("env_last", env_last);           // ถ้าต้องการ persistent: global.set("env_last", env_last, "file");
        node.status({ fill: "green", shape: "dot", text: `T=${temp} H=${hum}` });
        return null;
    }
}
return null;

// Rename by Tray (robust)
const fs = global.get('fs');
const path = global.get('path');

if (!fs || !path) {
    node.error("global fs/path not found. Please add functionGlobalContext in settings.js and restart Node-RED.");
    return msg;
}

// 1) หา filepath ให้ได้ก่อน
let filepath = msg.filepath;

// ถ้ายังไม่มี ลองดูจาก msg.payload (เผื่อยังเป็น JSON string ของ capture.py)
if ((!filepath || typeof filepath !== 'string') && msg.payload) {
    try {
        const p = (typeof msg.payload === 'string') ? JSON.parse(msg.payload) : msg.payload;
        if (p && typeof p.filepath === 'string') filepath = p.filepath;
    } catch (e) { /* ignore */ }
}

if (!filepath || typeof filepath !== 'string') {
    node.warn("Rename: filepath missing. Skip rename.");
    return msg; // ไม่ทำอะไรต่อ ปล่อยผ่าน
}

// 2) เตรียม meta สำหรับตั้งชื่อ
const meta = msg.meta || {};
const plant = meta.plant_id || 'PLANT-01';

// ปกติเราจะเก็บ tray เป็น 'TRAY-01' หรือเป็นเลข ให้ normalize เป็น 2 หลัก
let trayNum =
    meta.tray_id ?? meta.tray ??
    (typeof msg.tray === 'number' ? msg.tray : null); // เผื่อโหนดก่อนหน้าตั้งมา

let tray2 = '01';
if (trayNum != null) {
    const n = String(trayNum).replace(/[^\d]/g, '');
    if (n) tray2 = String(parseInt(n, 10)).padStart(2, '0');
}

const cell = meta.cell_id || 'C-XX';

// 3) คำนวณชื่อใหม่ + rename
const dir = path.dirname(filepath);
const ts = Math.floor(Date.now() / 1000);
const base = `${plant}_T-${tray2}_C-${cell}_${ts}.jpg`;
const newPath = path.join(dir, base);

try {
    fs.renameSync(filepath, newPath);
    msg.filepath = newPath;

    if (typeof msg.public_url === 'string') {
        // แทนชื่อไฟล์ท้าย URL
        msg.public_url = msg.public_url.replace(/[^\/\\]+$/, base);
    }
    node.status({ fill: "green", shape: "dot", text: base });
} catch (e) {
    node.warn("Rename failed: " + e.message);
}

return msg;

// ตั้งค่า limit ดีฟอลต์ 50 แล้วส่งต่อไปใช้โหนดหลัก
msg.req = msg.req || { query: {} };
msg.req.query = msg.req.query || {};
if (!msg.req.query.limit) msg.req.query.limit = "50";
return msg;

// List Media (FS → JSON) — fixed & hardened
const fs   = global.get('fs');
const path = global.get('path');

function normTray(q) {
  if (q == null) return null;
  const n = String(q).replace(/[^\d]/g, '');
  if (!n) return null;
  return 'TRAY-' + String(parseInt(n, 10)).padStart(2, '0');
}

// รับ date ได้ทั้ง "YYYY/MM/DD" หรือ "YYYY-MM-DD"
function normalizeDatePath(s) {
  if (!s) return null;
  s = String(s).trim();
  // กรองเฉพาะตัวเลข เครื่องหมาย / และ -
  s = s.replace(/[^\d/-]/g, '');
  // แทนที่ - เป็น /
  s = s.replace(/-/g, '/');
  // ตัดให้เหลือ YYYY/MM/DD
  const m = s.match(/^(\d{4})\/(\d{2})\/(\d{2})/);
  if (!m) return null;
  return `${m[1]}/${m[2]}/${m[3]}`;
}

const baseDir = "C:/AppServ/www/minijec/media";
const q = (msg.req && msg.req.query) ? msg.req.query : {};
const limit = Math.max(0, parseInt(q.limit || "0", 10));
const trayWant = normTray(q.tray);

// กำหนดโฟลเดอร์ย่อย (yyyy/mm/dd)
let sub = normalizeDatePath(q.date);
if (!sub) {
  const d = new Date();
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  sub = `${yyyy}/${mm}/${dd}`;
}
const dir = path.join(baseDir, ...sub.split('/'));

let out = [];
if (fs && path && fs.existsSync(dir)) {
  const names = fs.readdirSync(dir).filter(n => /\.(jpg|jpeg|png)$/i.test(n));
  for (const name of names) {
    const fp = path.join(dir, name);
    let st;
    try {
      st = fs.statSync(fp);
    } catch (e) {
      continue; // ไฟล์เพิ่งถูกย้าย/ลบ ข้ามไป
    }

    // รองรับชื่อไฟล์มาตรฐาน: PLANT-01_T-03_C-A1_1758559602.jpg
    const m = name.match(/^(PLANT-\d+)_T-(\d{2})_C-([A-Za-z0-9-]+)_(\d+)\.(jpg|jpeg|png)$/i);

    const item = {
      id: name,
      filename: name,
      size: st.size,
      mtime: st.mtimeMs, // ms
      url: `/minijec/media/${sub}/${name}`
    };

    if (m) {
      item.plant_id = m[1];
      item.tray_id  = 'TRAY-' + m[2];
      item.cell_id  = m[3];
      item.ts       = Number(m[4]); // seconds since epoch (จากชื่อไฟล์)
    }

    if (trayWant && item.tray_id !== trayWant) continue;
    out.push(item);
  }

  // ✅ แก้บั๊ก: เทียบเวลาให้เป็นหน่วยเดียวกัน (ms) ก่อน sort
  const toMs = (it) => (it.ts != null ? it.ts * 1000 : (it.mtime || 0));
  out.sort((a, b) => toMs(b) - toMs(a));

  if (limit > 0) out = out.slice(0, limit);
}

msg.headers = {
  "Content-Type": "application/json; charset=utf-8",
  "Access-Control-Allow-Origin": "*",
  "Cache-Control": "no-store, no-cache, must-revalidate, max-age=0"
};
msg.payload = out;
return msg;

if (Buffer.isBuffer(msg.payload)) msg.payload = msg.payload.toString();
msg.payload = (msg.payload||'').trim();
if (!msg.payload) msg.payload = '[]';
msg.headers = Object.assign({}, msg.headers, { 'Content-Type': 'application/json; charset=utf-8' });
return msg;

let txt = msg.payload; if (Buffer.isBuffer(txt)) txt = txt.toString(); txt = (txt||'').trim() || '[]';
let arr; try { arr = JSON.parse(txt); } catch(e){ arr = []; }
const q = (msg.req && msg.req._parsedUrl && msg.req._parsedUrl.query) || '';
const params = new URLSearchParams(q);
const N = Math.max(1, Math.min(200, Number(params.get('limit')||20)));
const items = (Array.isArray(arr)?arr:[]).slice(0,N).map(it=>{
  const id = (it.filename||'').replace(/\.(jpg|jpeg|png)$/i,'');
  const m = (it.filename||'').match(/^(PLANT-[0-9]+)/i);
  const plant_id = m ? m[1] : 'PLANT-01';
  return {
    id,
    plant_id,
    tray_id: '-',
    cell_id: '-',
    seed_count: null,
    area_px: null,
    greenness: null,
    captured_at: it.modified,
    url: (it.url||'').replace('\\','/')
  };
});
msg.payload = JSON.stringify({ items });
msg.headers = Object.assign({}, msg.headers, { 'Content-Type': 'application/json; charset=utf-8' });
return msg;

const fs = global.get("fs");
const path = global.get("path");
const BASE = "C:/AppServ/www/minijec/media";

function countToday() {
  try {
    if (!fs || !path) return 0;
    const d = new Date();
    const yyyy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, "0");
    const dd = String(d.getDate()).padStart(2, "0");
    const dir = path.join(BASE, yyyy.toString(), mm, dd);
    if (!fs.existsSync(dir)) return 0;
    const names = fs.readdirSync(dir);
    const exts = new Set([".jpg", ".jpeg", ".png"]);
    let n = 0;
    for (const name of names) {
      const ext = path.extname(name).toLowerCase();
      if (exts.has(ext)) n++;
    }
    return n;
  } catch (e) {
    node.warn("countToday error: " + e.message);
    return 0;
  }
}

const last = global.get("env_last") || {};
msg.summary = {
  images_today: countToday(),
  seeds_total: null,   // จะเติมทีหลังจาก Influx
  avg_per_cell: null,   // จะเติมทีหลังจาก Influx
  temp_c: (typeof last.temp_c === "number") ? last.temp_c : null,
  humidity: (typeof last.humidity === "number") ? last.humidity : null
};
return msg;

// robust: id รับได้ทั้ง "base name" และ "ชื่อไฟล์พร้อม .jpg/.png"

let txt = msg.payload;
if (Buffer.isBuffer(txt)) txt = txt.toString();
txt = (txt || '').trim() || '[]';

let arr; try { arr = JSON.parse(txt); } catch (e) { arr = []; }

// อ่าน id จาก query
const q = (msg.req && msg.req.query) ? msg.req.query : {};
const id = String(q.id || "").trim();
if (!id) {
  msg.statusCode = 400;
  msg.headers = { 'Content-Type': 'application/json; charset=utf-8', 'Access-Control-Allow-Origin': '*' };
  msg.payload = { ok: false, error: 'id required' };
  return msg;
}

// เตรียมทั้งแบบมีนามสกุลและแบบตัดนามสกุล
const idLower = id.toLowerCase();
const idBaseLower = idLower.replace(/\.(jpg|jpeg|png)$/i, '');

let found = null;
for (const it of (arr || [])) {
  const fname = String(it.filename || '');
  const lower = fname.toLowerCase();
  const base = lower.replace(/\.(jpg|jpeg|png)$/i, '');
  if (lower === idLower || base === idBaseLower) { found = it; break; }
}

if (!found) {
  msg.statusCode = 404;
  msg.headers = { 'Content-Type': 'application/json; charset=utf-8', 'Access-Control-Allow-Origin': '*' };
  msg.payload = { ok: false, error: 'not found' };
  return msg;
}

// ส่งฟิลด์ที่หน้า image.html ต้องการ
const out = {
  ok: true,
  id: (found.filename || '').replace(/\.(jpg|jpeg|png)$/i, ''),
  filename: found.filename || '',
  mtime: found.modified || found.mtime || null,   // ส่วนใหญ่เป็น ISO string
  size: Number(found.size) || 0,
  url: String(found.url || '').replace(/\\/g, '/')
};

msg.headers = { 'Content-Type': 'application/json; charset=utf-8', 'Access-Control-Allow-Origin': '*' };
msg.payload = out;   // ปล่อยเป็น object ได้เลย
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
let sum = 0, cnt = 0;
for (const r of rows) {
  const v = Number(r._value);
  if (Number.isFinite(v)) { sum += v; cnt++; }
}
const s = (msg.summary && typeof msg.summary === 'object') ? msg.summary : {};
s.seeds_total = cnt ? sum : 0;
s.avg_per_cell = cnt ? (sum / cnt) : null;

msg.headers = {
  "Content-Type": "application/json; charset=utf-8",
  "Access-Control-Allow-Origin": "*"
};
msg.payload = s;
return msg;

// Ensure Analyze — รับข้อความจาก stdout หรือ stderr ก็ได้
let s = msg.payload;
if (Buffer.isBuffer(s)) s = s.toString();
s = (s || '').trim();

// ข้ามบรรทัดที่ไม่ใช่ JSON (เช่น warning)
let obj = null;
if (s) {
    try { obj = JSON.parse(s); } catch (e) { obj = null; }
}
if (!obj || typeof obj !== 'object') {
    // ไม่ใช่ JSON → ทิ้งข้อความนี้ไป (จะมีข้อความใหม่ไหลมาอีกจากอีก output)
    return null;
}

// บังคับเป็นตัวเลข
['area_px', 'greenness', 'seed_count'].forEach(k => {
    if (obj[k] != null) obj[k] = Number(obj[k]);
});

msg.payload = obj;
return msg;

/**
 * Output #1 -> SMTP (e-mail)
 * Output #2 -> HTTP Response (JSON)
 */
const fs = global.get('fs');
const path = global.get('path');

// === CONFIG ===
const MEDIA_BASE = "C:/AppServ/www/minijec/media";
const PUBLIC_BASE = "http://172.20.10.4";
const PUBLIC_PREFIX = "/minijec";

// === Helper: HTTP response ===
function httpOK(msgIn, data) {
  return {
    req: msgIn.req, res: msgIn.res,
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    },
    payload: data
  };
}
function httpErr(msgIn, status, message) {
  return {
    req: msgIn.req, res: msgIn.res,
    statusCode: status,
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type"
    },
    payload: { ok: false, error: message }
  };
}

// === Helper: อ่านอีเมลจาก body/query ===
function readEmail(msg) {
  let body = msg.payload;
  if (Buffer.isBuffer(body)) body = body.toString();
  if (typeof body === "string") { try { body = JSON.parse(body); } catch (e) { } }
  const fromBody = (body && typeof body === "object") ? (body.email || body.to) : null;
  const fromQuery = (msg.req && msg.req.query) ? (msg.req.query.email || msg.req.query.to) : null;
  return String(fromBody || fromQuery || "").trim();
}

if (!fs || !path) {
  node.warn("global fs/path not found");
  return [null, httpErr(msg, 500, "server fs/path not available")];
}

const email = readEmail(msg);
if (!email) return [null, httpErr(msg, 400, "missing email")];

// === โฟลเดอร์วันที่ ===
const now = new Date();
const y = now.getFullYear();
const m = String(now.getMonth() + 1).padStart(2, "0");
const d = String(now.getDate()).padStart(2, "0");
const dayDir = path.join(MEDIA_BASE, y.toString(), m, d);

// === หาไฟล์ล่าสุดต่อถาด ===
function latestPerTray() {
  if (!fs.existsSync(dayDir)) return [];
  const names = fs.readdirSync(dayDir).filter(n => /\.(jpg|jpeg|png)$/i.test(n));
  const map = {};
  for (const name of names) {
    const mm = name.match(/^(PLANT-\d+)_T-(\d{2})_C-([A-Za-z0-9-]+)_(\d+)\.(jpg|jpeg|png)$/i);
    if (!mm) continue;
    const tray = "TRAY-" + mm[2];
    const ts = Number(mm[4]) || 0;
    if (!map[tray] || ts > map[tray].ts) {
      map[tray] = { name, ts };
    }
  }
  return Object.entries(map)
    .map(([tray, o]) => ({
      tray,
      filename: o.name,
      ts: o.ts,
      url: PUBLIC_BASE + PUBLIC_PREFIX + "/media/" + y + "/" + m + "/" + d + "/" + o.name,
      time: new Date(o.ts * 1000).toLocaleString()
    }))
    .sort((a, b) => b.ts - a.ts)
    .slice(0, 8);
}

const items = latestPerTray();

// === Mock metrics (TODO: ดึงจริงจาก InfluxDB ถ้าพร้อม) ===
for (const it of items) {
  it.area_px = Math.floor(Math.random() * 20000);
  it.greeness = (Math.random() * 1).toFixed(2);
  it.humidity = (60 + Math.random() * 20).toFixed(1);
  it.seed_count = Math.floor(Math.random() * 40);
  it.temp_c = (25 + Math.random() * 10).toFixed(1);
}

// === HTML table ===
function htmlRows(items) {
  return items.map(it =>
    "<tr>" +
    "<td>" + it.tray + "</td>" +
    "<td>" + it.area_px + "</td>" +
    "<td>" + it.greeness + "</td>" +
    "<td>" + it.humidity + "</td>" +
    "<td>" + it.seed_count + "</td>" +
    "<td>" + it.temp_c + "°C</td>" +
    "<td>" + it.time + "</td>" +
    "<td><a href=\"" + it.url + "\" target=\"_blank\">เปิดรูป</a></td>" +
    "</tr>"
  ).join("");
}

let htmlString = "";
htmlString += "<div style=\"font:14px/1.6 -apple-system,Segoe UI,Roboto,Arial\">";
htmlString += "<h2>🌱 Seed Monitor · รายงานล่าสุด 8 ถาด</h2>";
htmlString += "<div>" + now.toLocaleString() + "</div>";
if (items.length) {
  htmlString += "<table cellspacing=\"0\" cellpadding=\"6\" border=\"1\" style=\"border-collapse:collapse;border:1px solid #ddd\">";
  htmlString += "<thead><tr><th>Tray</th><th>Area(px)</th><th>Greeness</th><th>Humidity</th><th>Seed Count</th><th>Temp</th><th>เวลา</th><th>ลิงก์</th></tr></thead>";
  htmlString += "<tbody>" + htmlRows(items) + "</tbody>";
  htmlString += "</table>";
} else {
  htmlString += "<p>วันนี้ยังไม่มีข้อมูล</p>";
}
htmlString += "</div>";

// === Output ===
const mailOut = {
  to: email,
  topic: "🌱 Seed Monitor · รายงานล่าสุด 8 ถาด",
  payload: htmlString,
  payloadType: "html"  // สำคัญ!
};
const httpOut = httpOK(msg, { ok: true, count: items.length, to: email, items });

node.status({ fill: "green", shape: "dot", text: "mail→ " + email + " (" + items.length + ")" });
return [mailOut, httpOut];

// ดึงค่าที่คำนวณจาก analyze
const d = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};

// 1) พยายามใช้ tray จาก Compose Influx Point (ใส่ไว้ใน msg.tags)
let tray = (msg.tags && msg.tags.tray_id) || d.tray || null;

// 2) ถ้าไม่มี ให้ดึงจากชื่อไฟล์ที่ Rename by Tray ตั้งให้ เช่น
// PLANT-01_T-03_C-A1_1758559602.jpg  => TRAY-03
if (!tray) {
    const src = ((msg.filepath || '') + ' ' + (msg.public_url || '')).toString();
    const m = src.match(/_T-(\d{2})_/);
    if (m) tray = 'TRAY-' + m[1];
}

// 3) กันเคสว่าง
tray = tray || 'TRAY-XX';

// 4) ทำความสะอาดและบังคับชนิดตัวเลขก่อนใส่ SQL
const q = (n, def = 0) => {
    const v = Number(n);
    return Number.isFinite(v) ? v : def;
};

const traySafe = tray.replace(/'/g, "''");

// ⚠ คอลัมน์ในตารางของคุณสะกด greeness (n เดียว)
msg.topic = `
INSERT INTO tray_data (tray, area_px, greeness, seed_count, temp_c, humidity, ts)
VALUES ('${traySafe}', ${q(d.area_px)}, ${q(d.greenness)}, ${q(d.seed_count)}, ${q(d.temp_c)}, ${q(d.humidity)}, NOW())
`;

return msg;

let d = msg.payload;  // { tray, area_px, greenness, seed_count, temp_c, humidity }

const tray = (d.tray || 'TRAY-XX').replace(/'/g,"''");  // กัน ' ในชื่อถาด

// !! ใช้ชื่อคอลัมน์ให้ตรงตาราง: greeness (n เดียว)
msg.topic = `
INSERT INTO tray_data (tray, area_px, greeness, seed_count, temp_c, humidity, ts)
VALUES ('${tray}', ${d.area_px}, ${d.greenness}, ${d.seed_count}, ${d.temp_c}, ${d.humidity}, NOW())
`;

return msg;

// Expose tray_id into payload for downstream nodes
const p = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};
p.tray = (msg.tags && msg.tags.tray_id)
    || (msg.meta && (msg.meta.tray_id || msg.meta.tray))
    || 'TRAY-XX';
msg.payload = p;
return msg;

// อ่าน limit จาก query, ค่าเริ่มต้น 8
const q = (msg.req && msg.req.query) ? msg.req.query : {};
const lim = Math.max(1, Math.min(50, Number(q.limit || 8)));
msg.topic = `
  SELECT tray, area_px, greeness, seed_count, temp_c, humidity, ts
  FROM tray_data
  WHERE (tray, ts) IN (
    SELECT t.tray, MAX(t.ts) AS ts
    FROM tray_data t
    GROUP BY t.tray
  )
  ORDER BY ts DESC
  LIMIT ${lim}
`;
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
// แปลงรูปแบบให้อ่านง่ายฝั่งเว็บ
const items = rows.map(r => ({
  tray: r.tray,
  area_px: Number(r.area_px)||0,
  greenness: Number(r.greeness)||0,   // คอลัมน์ในตารางสะกด greeness
  seed_count: Number(r.seed_count)||0,
  temp_c: Number(r.temp_c)||0,
  humidity: Number(r.humidity)||0,
  ts: r.ts
}));
msg.headers = {
  "Content-Type": "application/json; charset=utf-8",
  "Access-Control-Allow-Origin": "*",
  "Cache-Control": "no-store, no-cache, must-revalidate, max-age=0"
};
msg.payload = { items };
return msg;
